import std.sort: sort;

func solve(nums: Array<Int64>): Int64 {
    let n = nums.size();
    var B = [n:Int64]();
    for i: Int in 0..<n {
        if nums[i] >= 0 {
            B[i] = nums[i];
        } else {
            B[i] = -nums[i];
        }
    }
    sort(B);

    var ptr: Int = 0;
    var total: Int64 = 0;
    for j: Int in 0..<n {
        while ptr < j and (B[ptr] * 2 < B[j]) {
            ptr = ptr + 1;
        }
        total = total + Int64(j - ptr);
    }
    return total;
}
```

