func solve(nums: Array<Int64>) -> Int64 {
    let n = nums.count
    if n < 2 { 
        return 0 
    }
    var b = nums.map { $0 < 0 ? -$0 : $0 }
    b.sort()
    var total: Int64 = 0
    for j in 0..<n {
        let threshold = (b[j] + 1) / 2
        var low = 0
        var high = j
        while low < high {
            let mid = (low + high) / 2
            if b[mid] < threshold {
                low = mid + 1
            } else {
                high = mid
            }
        }
        total += Int64(j - low)
    }
    return total
}
```

